"""Контракты сигналов, шумов, фильтров."""from __future__ import annotationsfrom abc import ABC, abstractmethodfrom typing import Anyfrom .types import Signalclass ISignal(ABC):    name: str    description: str    params_schema: dict[str, dict[str, Any]]    @abstractmethod    def generate(self, **params: Any) -> Signal: ...class INoise(ABC):    name: str    description: str    params_schema: dict[str, dict[str, Any]]    @abstractmethod    def apply(self, signal: Signal, **params: Any) -> Signal: ...class IFilter(ABC):    name: str    description: str    params_schema: dict[str, dict[str, Any]]    @abstractmethod    def apply(self, noisy: Signal, **params: Any) -> Signal: ...